oxy_webhelp_navlinks = {"instant_recovery_vSphere_VMs-d23535e23647":{"topics":[{"title":"Recovering bulk vSphere VMs to current compute resources","shortdesc":"<p class=\"shortdesc\">Use Instant Recovery to recover multiple vSphere virtual machines with Exports to         current compute resources. Instant Recovery is a workflow option that you can use to quickly         replace a source virtual machine with a new virtual machine using a snapshot.<\/p>","href":"saas\/recovering_mulitple_VMs_using_Live_Mounts.html","attributes":{"data-id":"recovering_mulitple_VMs_using_Live_Mounts"},"menu":{"hasChildren":false},"tocID":"recovering_mulitple_VMs_using_Live_Mounts-d23535e23658","topics":[]},{"title":"Selecting a new compute resource for vSphere VMs ","shortdesc":"<p class=\"shortdesc\">Use Instant Recovery to perform an instant recovery of multiple vSphere virtual         machines by selecting a new target compute resource for all selected virtual         machines.<\/p>","href":"saas\/select_a_new_VM_compute_resource.html","attributes":{"data-id":"select_a_new_VM_compute_resource"},"menu":{"hasChildren":false},"tocID":"select_a_new_VM_compute_resource-d23535e23669","topics":[]}]}};